1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 1.1;
3	const FP_EPSILON = 1e-9;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  rune: 25,
9	};
10	
11	type Item = { type: string };
12	type Step = { op: "quote"; items: Item[] };
13	type Scenario = { steps: Step[] };
14	
15	const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type];
16	
17	const sum = (numbers: number[]): number =>
18	  numbers.reduce((acc, n) => acc + n, 0);
19	
20	// round up to whole G in MHPCO's favor, using epsilon to fight FP error
21	const roundUpInMHPCOFavor = (amount: number): number =>
22	  Math.ceil(amount - FP_EPSILON);
23	
24	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
25	const COMPONENT_BLOCK_SIZE = 3;
26	const COMPONENT_BLOCK_PRICE = 60;
27	
28	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
29	
30	const countByType = (items: Item[]): Map<string, number> =>
31	  items.reduce(
32	    (acc, item) => acc.set(item.type, (acc.get(item.type) ?? 0) + 1),
33	    new Map<string, number>(),
34	  );
35	
36	const componentGroupPremium = (type: string, count: number): number =>
37	  count === COMPONENT_BLOCK_SIZE
38	    ? COMPONENT_BLOCK_PRICE
39	    : count * BASE_PREMIUM[type];
40	
41	const itemsBasePremium = (items: Item[]): number => {
42	  const components = items.filter(isComponent);
43	  const others = items.filter((i) => !isComponent(i));
44	  const componentsBase = sum(
45	    [...countByType(components)].map(([type, count]) =>
46	      componentGroupPremium(type, count),
47	    ),
48	  );
49	  return componentsBase + sum(others.map(itemBasePremium));
50	};
51	
52	const quote = (step: Step): { premium: number } => {
53	  const policyBase = itemsBasePremium(step.items);
54	  const total = policyBase * FIRST_INSURANCE_SURCHARGE + PROCESSING_FEE;
55	  return { premium: roundUpInMHPCOFavor(total) };
56	};
57	
58	export const runScenario = (input: unknown): unknown => {
59	  const scenario = input as Scenario;
60	  return { results: scenario.steps.map(quote) };
61	};
